insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-2-business-planning:tf:cbcae14f', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tf', 'tf', 1, '{"question": "There is a legal requirement for all businesses to produce a business plan."}'::jsonb, '{"answer": false, "explain": "FALSE. There is no legal requirement to produce a business plan. However, it is strongly advisable — particularly for new businesses seeking external finance — as banks will rarely lend without one."}'::jsonb),
('business:1-2-business-planning:learn:238e772c', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must be able to define accurately in the exam. Learn each one precisely — examiners expect specific language.</p>\n<ul>\n  <li><strong>Business Plan:</strong> A document which sets out details of the product or service being sold, how it will be financed, how it will be marketed, and the findings of market research.</li>\n  <li><strong>Finance:</strong> A business word used instead of money. The finance needed to start a business is the money required to buy the resources needed.</li>\n  <li><strong>Markets:</strong> Where a business sells its goods and services.</li>\n  <li><strong>Resources:</strong> The things a business needs to make it work, including finance, staff and materials.</li>\n  <li><strong>Operate:</strong> A term used to explain how a business works.</li>\n  <li><strong>Success:</strong> For a business, can take many forms, including making profit, surviving and providing a good service to customers.</li>\n  <li><strong>Aims and Objectives:</strong> Statements of what the business is trying to achieve (e.g. make a profit, expand, increase market share, survive).</li>\n  <li><strong>SMART Objectives:</strong> Objectives that are Specific, Measurable, Achievable, Realistic and Time-bound.</li>\n</ul>", "question": "What does the ''M'' in SMART objectives stand for?", "options": ["Measurable", "Marketable", "Motivational", "Manageable"]}'::jsonb, '{"answer": 0, "explain": "The M in SMART stands for Measurable — one of the five criteria (Specific, Measurable, Achievable, Realistic, Time-bound) listed in the Key Terms card."}'::jsonb),
('business:1-2-business-planning:learn:188126b3', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "The Purpose of Planning Business Activity", "reading": "<p>Every business — whether brand new or well established — needs to plan. Planning is a vital part of the successful start-up and development of a business. There are two core purposes:</p>\n<ul>\n  <li><strong>Reduce the risk of failure:</strong> Starting a business is risky. There may be competitors and customers might not want the product. Writing a business plan forces entrepreneurs to think through potential problems before they happen, reducing (but not eliminating) risk.</li>\n  <li><strong>Help a business to be as successful as possible:</strong> Thinking carefully about all aspects of running a business allows entrepreneurs to reflect on what they are proposing. The greater the care and thought given to this process, the greater the chance of success.</li>\n</ul>\n<p><strong>When is a business plan written?</strong> A business plan is normally written <strong>before a business starts</strong>, or when there is a major change in what the business plans to do (e.g. expanding into a new market, launching a new product).</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Electric Cars & Business Planning</h4>\n  <p>By 2030, no new petrol or diesel cars can be sold in the UK. Every car manufacturer — from Ford to Toyota — must plan carefully for this enormous change. Billions of pounds are being spent on changing production methods, and this cannot happen overnight. Careful planning ensures manufacturers meet the 2030 deadline without making costly mistakes in an intensely competitive market.</p>\n  <p><strong>Takeaway:</strong> Even large, established businesses must plan when facing major change. The scale of investment makes planning essential — getting it wrong could be catastrophic.</p>\n</div>", "question": "According to the two core purposes of business planning, besides reducing the risk of failure, what is the other main purpose?", "options": ["Satisfy a legal requirement for trading", "Help the business be as successful as possible", "Prevent competitors from entering the market", "Guarantee the business will make a profit"]}'::jsonb, '{"answer": 1, "explain": "The card states planning serves two purposes: reducing the risk of failure and helping the business be as successful as possible."}'::jsonb),
('business:1-2-business-planning:learn:a05fbde6', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "The Contents of a Business Plan", "reading": "<p>A business plan is not a standardised document — it is adapted to the specific circumstances of each business. However, most plans will cover the following key areas:</p>\n<ul>\n  <li><strong>The Business Idea:</strong> What the business will produce and sell. Is it a totally new idea or a development of an existing product/service?</li>\n  <li><strong>The People Running the Business:</strong> Details of who is involved and their relevant experience. Banks and investors are far more likely to back a plan from someone with proven experience.</li>\n  <li><strong>Market Research:</strong> Evidence that consumers want the product or service. Includes target market, pricing, how the product will be sold (online, shops, etc.) and promotional plans.</li>\n  <li><strong>Finance:</strong> How much money is needed, what it will be spent on, and where it will come from (e.g. owner''s savings, bank loan, overdraft, selling shares).</li>\n  <li><strong>Aims and Objectives:</strong> What the business wants to achieve and by when. These should be SMART.</li>\n  <li><strong>The Target Market:</strong> Who the business is selling to — age, gender, income level, etc.</li>\n  <li><strong>Competitors:</strong> Who the competitors are and how the business will differentiate itself (better quality, lower prices, unique features).</li>\n  <li><strong>Resources Needed:</strong> Equipment, premises, staff — everything required to operate the business.</li>\n</ul>\n<p>⚠️ <strong>What is NOT in a business plan:</strong> Personal hobbies of the owners, dates of birth, favourite school subjects, or titles of business textbooks.</p>", "question": "Which of the following would NOT normally be included in a business plan?", "options": ["The owners'' dates of birth", "The target market", "How the business will be financed", "Details of competitors"]}'::jsonb, '{"answer": 0, "explain": "The card explicitly states personal details like dates of birth are NOT included in a business plan, unlike the target market, finance and competitors."}'::jsonb),
('business:1-2-business-planning:learn:ca67324e', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "The Role of a Business Plan", "reading": "<p>A business plan serves several important roles beyond simply being a written document. Understanding these roles helps you answer \"explain the purpose of…\" questions at a higher level.</p>\n<ul>\n  <li><strong>Identifying Markets:</strong> Forces the business to think clearly about who it is targeting. This shapes marketing decisions — the type of advertising, the price point, and the distribution channel all depend on the target market.</li>\n  <li><strong>Helping with Finance:</strong> Banks are more likely to lend money if they can see a detailed, well-thought-out plan. It demonstrates that the owners have considered all aspects of the business and gives lenders confidence they will be repaid.</li>\n  <li><strong>Identifying Resources:</strong> Requires owners to think about what equipment, premises, and staff they need to operate. Without this, a potential investor may view the business as too risky and refuse to invest.</li>\n  <li><strong>Achieving Aims and Objectives:</strong> Setting out aims with a timeline gives the business a clear direction. Without targets, there is no way to measure success or know when things are going wrong.</li>\n  <li><strong>Reducing Risk:</strong> Though a business plan cannot eliminate risk, it significantly reduces it by ensuring the business has thought through the key challenges in advance.</li>\n</ul>", "question": "Which role of a business plan best explains why banks are more willing to lend money to a business?", "options": ["Identifying markets, since it lists advertising slogans", "Reducing risk, since it removes all risk from trading", "Helping with finance, showing it''s carefully thought through", "Achieving aims and objectives, guaranteeing targets are met"]}'::jsonb, '{"answer": 2, "explain": "The ''Helping with Finance'' role explains that banks lend more readily when they see a detailed, well-thought-out plan, giving them confidence they will be repaid."}'::jsonb),
('business:1-2-business-planning:learn:2862cde3', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of a Business Plan", "reading": "<p>For evaluation questions, you must be able to argue both sides. Here are the key points for and against producing a business plan:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Reduces risk:</strong> Potential problems are identified before money is spent, giving the business a better chance of surviving.</div>\n    <div class=\"pro-item\"><strong>Secures finance:</strong> Banks and investors will rarely lend money without seeing a detailed plan — it is often essential for external funding.</div>\n    <div class=\"pro-item\"><strong>Sets clear direction:</strong> SMART objectives give the business measurable targets and a timeline, helping to keep focus and motivate staff.</div>\n    <div class=\"pro-item\"><strong>Identifies resources:</strong> Ensures the business has considered what it needs to operate, so it is not caught short once trading begins.</div>\n    <div class=\"pro-item\"><strong>Useful for evaluation:</strong> The plan can be used to monitor progress and identify when the business is falling short of its targets.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Time-consuming:</strong> Writing a thorough business plan takes significant time — time that could be spent running the business or serving customers.</div>\n    <div class=\"con-item\"><strong>Can be inaccurate:</strong> Forecasts are based on assumptions. If the market changes or competitors respond unexpectedly, the plan may quickly become outdated.</div>\n    <div class=\"con-item\"><strong>No guarantee of success:</strong> Even the best business plan cannot eliminate all risk. Unforeseen events (e.g. economic recessions, new competitors) can still cause a business to fail.</div>\n    <div class=\"con-item\"><strong>Opportunity cost:</strong> The time spent writing a plan has an opportunity cost — the owner cannot do other productive activities during that time.</div>\n  </div>\n</div>", "question": "Which of the following is a disadvantage of writing a business plan mentioned in this card?", "options": ["It guarantees business success", "It is time-consuming to produce", "It removes the need to secure finance", "It prevents competitors from copying ideas"]}'::jsonb, '{"answer": 1, "explain": "One disadvantage listed is that writing a thorough business plan is time-consuming, taking time that could be spent running the business."}'::jsonb),
('business:1-2-business-planning:learn:4cabb99d', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "Evaluating a Business Plan", "reading": "<p>In 9-mark evaluation questions, you will be asked to assess whether a specific business plan is effective or whether a business should write one. Use this framework to structure your thinking:</p>\n<ul>\n  <li><strong>What is included?</strong> Does the plan cover the core areas — market research, finance, target market, competitors, resources, objectives?</li>\n  <li><strong>What is missing?</strong> Any missing section could be a critical weakness, especially if it relates to the business''s specific situation (e.g. no competitor analysis for a business entering a crowded market).</li>\n  <li><strong>Are objectives SMART?</strong> Vague targets like \"make a profit\" or \"grow the business\" are not measurable. Look for specific figures and timelines.</li>\n  <li><strong>Is the plan relevant to the business context?</strong> A plan for a new start-up needs more detail than a plan for an established business making a minor change.</li>\n  <li><strong>Is the time cost justified?</strong> Weigh the benefit of having a plan against the opportunity cost of the time spent writing it.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Dunning Golf Club</h4>\n  <p>Dunning Golf Club produced a plan to increase its membership and profitability. The plan included: improving the golf club facilities, offering more benefits to paid-up members (e.g. subsidised lessons), using outside caterers to ensure better and cheaper catering, and more clearly stated priorities for the future and how these would be financed.</p>\n  <p><strong>Takeaway:</strong> This plan covers several important areas (finance, marketing, customer benefits, objectives) but could be criticised for not explicitly mentioning market research or a detailed competitor analysis. Are the targets SMART? They mention goals but without specific figures or deadlines.</p>\n</div>", "question": "When evaluating whether a business plan is effective, what should you check regarding its objectives?", "options": ["Whether it is longer than five pages", "Whether the objectives are SMART", "Whether it was submitted to a bank", "Whether it was written by a professional consultant"]}'::jsonb, '{"answer": 1, "explain": "The evaluation framework asks whether objectives are SMART — vague targets without specific figures or timelines, as seen in the Dunning Golf Club case study, are a weakness."}'::jsonb),
('business:1-2-business-planning:learn:ce68c4af', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'learn', 'mcq', 1, '{"readingTitle": "Business Planning for Different Types of Business", "reading": "<p>The importance and content of a business plan can vary significantly depending on the type of business. You may be asked to apply your knowledge to a specific business context.</p>\n<ul>\n  <li><strong>New Start-Up Business:</strong> A business plan is <em>especially</em> critical here. The business has no trading history, no existing customers, and typically needs external finance. Without a plan, a bank will not lend money and the founder has no way to judge whether the idea will work. The risk of failure is highest at the start-up stage.</li>\n  <li><strong>Large Established Business (e.g. Greggs, Ford):</strong> Planning is still vital when entering new markets, launching new products, or making major operational changes. Greggs used market data showing rising vegan numbers to plan and launch new products — this led to a 9.6% increase in sales.</li>\n  <li><strong>Expanding Business:</strong> When a successful business wants to grow (e.g. open new locations), a plan helps identify new resource needs, new competitors in the target area, and the finance required to fund expansion.</li>\n  <li><strong>Seasonal Business (e.g. Boots UK):</strong> Planning helps manage resource needs at different times of year — for example, recruiting temporary staff ahead of the Christmas period to match seasonal demand.</li>\n</ul>", "question": "Why is a business plan especially critical for a new start-up business, according to this card?", "options": ["It removes the need for market research", "It is legally required to be submitted to Companies House", "It has no trading history and usually needs external finance", "It guarantees the new business will succeed"]}'::jsonb, '{"answer": 2, "explain": "The card states a business plan is especially critical for a new start-up because it has no trading history and typically needs external finance, which banks won''t lend without a plan."}'::jsonb),
('business:1-2-business-planning:misc:f17c371a', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business plan is a thought or process — something the owner thinks about.</p><p><strong>✅ The correct idea:</strong> A business plan is specifically a document or written record. The Knowledge mark in long-answer questions requires you to describe it as a document, not just an idea or plan in the owner''s head.</p>", "question": "What must a business plan be described as, to earn the Knowledge mark?", "options": ["A thought or idea in the owner''s mind", "A verbal agreement between business partners", "A mental checklist used before trading", "A document or written record"]}'::jsonb, '{"answer": 3, "explain": "The misconception card corrects that a business plan is specifically a document, not a thought — this distinction is required for the Knowledge mark."}'::jsonb),
('business:1-2-business-planning:misc:572de9f6', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing a business plan means the business will definitely succeed.</p><p><strong>✅ The correct idea:</strong> A business plan reduces risk but cannot eliminate it. Always write ''reduces the risk of failure'' — never say it ''guarantees success'' or ''ensures the business will be profitable''.</p>", "question": "Which phrase correctly describes the effect of a business plan on risk?", "options": ["Eliminates all risk of failure", "Guarantees the business will succeed", "Reduces the risk of failure", "Has no effect on the level of risk"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that a plan guarantees success — it only reduces risk, and you should never claim it ''guarantees'' or ''ensures'' success."}'::jsonb),
('business:1-2-business-planning:misc:233ec8e1', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business plan has a fixed, standard format that every business follows.</p><p><strong>✅ The correct idea:</strong> A business plan is adapted to the specific circumstances of the business. There is no single correct format — the content depends on what the business needs to consider.</p>", "question": "Does every business plan follow the same fixed, standard format?", "options": ["It must follow an identical, standardised structure", "It is chosen randomly by each business owner", "It is set by strict government regulation", "It is closely adapted to a business''s specific needs"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception of a fixed format — a business plan is adapted to what the specific business needs to consider."}'::jsonb),
('business:1-2-business-planning:misc:f7498483', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> In an evaluate question about a business plan, simply listing what is in a plan gets full marks.</p><p><strong>✅ The correct idea:</strong> Evaluation questions require you to judge whether the plan is good or whether it is missing anything. You must consider whether the objectives are SMART and whether the missing sections matter given the specific business context.</p>", "question": "In an evaluate question, what must you do to earn full marks beyond listing the contents of a business plan?", "options": ["Copy the case study details out word for word", "Write as many sentences as possible about the plan", "Simply list every section included in the plan", "Judge whether the plan is effective and identify gaps"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that listing contents earns full marks — evaluate questions require judging the plan''s effectiveness, including whether objectives are SMART and what might be missing."}'::jsonb),
('business:1-2-business-planning:misc:a5b13974', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All businesses need to write a new business plan every year.</p><p><strong>✅ The correct idea:</strong> A business plan is written when a business starts or when a major change is planned (e.g. expansion, entering a new market). It is not an annual requirement — but it should be updated when significant changes occur.</p>", "question": "When should a business normally produce a new business plan?", "options": ["Every single year without exception", "Only after the business has already failed once", "At start-up, or when a major change is planned", "Only when a bank specifically requests one"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception of an annual requirement — a plan is written at start-up or when a major change (like expansion) is planned, and updated when significant changes occur."}'::jsonb),
('business:1-2-business-planning:misc:97dcc710', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Including personal information about the owners (hobbies, birth dates, favourite books) makes the business plan more complete.</p><p><strong>✅ The correct idea:</strong> Personal information is irrelevant and should not be included. Examiners specifically test this with true/false questions. Only business-relevant information belongs in the plan.</p>", "question": "Should personal information about the owners, such as hobbies or dates of birth, be included in a business plan?", "options": ["No, because including it breaks the law", "Yes, it makes the plan feel more complete and personal", "No, personal information is irrelevant to the business", "Yes, but only for larger business partnerships"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that personal details make a plan more complete — examiners specifically test with true/false questions that such information is irrelevant."}'::jsonb),
('business:1-2-business-planning:misc:ac73f8b1', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For the Application marks in a 9-mark question, you just need to mention the business name.</p><p><strong>✅ The correct idea:</strong> Application marks require you to use specific data from the case study — particularly numerical data. For example, calculating percentages from survey results or using specific figures mentioned in the text.</p>", "question": "What is required to earn Application marks in a 9-mark question?", "options": ["Writing the longest possible answer overall", "Repeating back the wording of the question", "Using specific numerical data from the study", "Simply mentioning the name of the business"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that naming the business is enough — Application marks require using specific data, especially numerical calculations, from the case study."}'::jsonb),
('business:1-2-business-planning:misc:b00d018d', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A conclusion in a 9-mark evaluation can just repeat the points already made.</p><p><strong>✅ The correct idea:</strong> To earn full Evaluation marks, the judgement must be explicit AND contextually justified. Simply repeating earlier points without making a clear decision earns only 1 mark out of 3. You must state your decision AND justify it using case study detail.</p>", "question": "To earn full Evaluation marks in a 9-mark question conclusion, what must you do?", "options": ["List a few extra advantages not mentioned before", "Ask the examiner an unanswered rhetorical question", "Simply repeat the analysis points already made", "State an explicit decision, justified in context"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that repeating points is enough — full Evaluation marks require an explicit, contextually-justified decision; repeating points without one earns only 1 of 3 marks."}'::jsonb),
('business:1-2-business-planning:tips:bb6daa39', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tips', 'mcq', 1, '{"readingTitle": "Define — 1 mark — A Business Plan is a DOCUMENT — Not a Thought", "reading": "<p>This is one of the most commonly missed marks on the paper. The Knowledge mark requires you to describe a business plan as a <strong>specific document or written record</strong> — not just an idea, thought, or process.</p>\n    <p><strong>❌ Bad Answer (0 marks):</strong><br/><em>\"A business plan is when a business thinks about what it wants to do.\"</em></p>\n    <p><strong>✅ Good Answer (1 mark):</strong><br/><em>\"A business plan is a document that sets out the aims, finance, market research, and marketing of a business.\"</em></p>\n    <p><strong>⚠️ Examiner''s Warning:</strong> Candidates who launched straight into pros and cons without defining what a business plan actually is frequently missed this mark. Always define key terms at the start of a long-answer question.</p>", "question": "According to this exam tip, what mistake do many candidates make in long-answer questions about business plans?", "options": ["They forget to write a conclusion", "They give far too many disadvantages", "They write too many calculations", "They skip the definition entirely"]}'::jsonb, '{"answer": 3, "explain": "The examiner''s warning notes candidates who jumped straight into pros and cons without first defining what a business plan is frequently missed the Knowledge mark."}'::jsonb),
('business:1-2-business-planning:tips:6e7b37a4', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Point + Link to Business = 2 Marks", "reading": "<p>For a 2-mark \"explain\" question, you need two things: a clear point AND a development that links it to the business or shows the impact.</p>\n    <p><strong>The Formula:</strong> State the benefit (1) → Explain how it helps the specific business (1)</p>\n    <p><strong>❌ Bad Answer (0–1 marks):</strong><br/><em>\"Planning helps Boots UK because it is organised.\"</em><br/>This is too vague — \"organised\" is not a business outcome.</p>\n    <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"Business planning helps Boots UK identify what resources (such as labour) are needed at specific times (1), so that when the store is at its busiest over Christmas, staffing levels match demand (1).\"</em></p>\n    <p><strong>🚫 Avoid:</strong> Do not confuse WHAT is planned with WHY planning is useful. The question asks for the purpose/advantage — not the contents.</p>", "question": "What is required to score full marks on a 2-mark ''explain'' question?", "options": ["A clear point linked to the business", "One long, unstructured paragraph", "A definition of the key term only", "Two completely unrelated points"]}'::jsonb, '{"answer": 0, "explain": "The formula for a 2-mark explain question is: state the benefit, then explain how it helps the specific business — point plus link."}'::jsonb),
('business:1-2-business-planning:tips:050b0286', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tips', 'mcq', 1, '{"readingTitle": "Quantitative Application — 2 marks — Use the Numbers — Don''t Just Quote Them", "reading": "<p>In 9-mark questions with data, <strong>two of the nine marks are for quantitative application</strong>. This means you must <strong>calculate or process</strong> the numbers — not just copy them out.</p>\n    <p><strong>The Formula:</strong> Perform any relevant calculation using the data provided.</p>\n    <p><strong>Examples of calculations from the SJ Salon question:</strong></p>\n    <ul>\n      <li>65% of customers have used SJ Salon since 2019 (130 ÷ 200 × 100)</li>\n      <li>42% of customers would consider trying the competitor if cheaper (84 ÷ 200 × 100)</li>\n      <li>Sam last wrote a business plan 10 years ago (2024 − 2014 = 10)</li>\n      <li>Writing the plan would take 75% of a working week (30 ÷ 40 × 100)</li>\n      <li>96 customers were NOT aware of the competitor (200 − 104 = 96)</li>\n    </ul>\n    <p><strong>⚠️ Key Rule:</strong> You need two separate calculations for 2 marks. Any valid calculation counts — even simple ones like 2 + 2 = 4 employees.</p>", "question": "In a 9-mark data-response question, how many separate calculations are typically needed to earn full quantitative application marks?", "options": ["Four", "One", "Two", "None — quoting the figures is enough"]}'::jsonb, '{"answer": 2, "explain": "The key rule states you need two separate calculations to earn the two quantitative application marks — simply quoting numbers is not enough."}'::jsonb),
('business:1-2-business-planning:tips:effd8550', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 2 marks — One Pro AND One Con = Full Analysis Marks", "reading": "<p>For the 2 analysis marks in a 9-mark question, examiners are looking for <strong>one business-facing advantage</strong> AND <strong>one business-facing disadvantage</strong> of writing a business plan.</p>\n    <p><strong>The Formula:</strong> One pro (1) + One con (1) = 2 marks</p>\n    <p><strong>✅ Good Analysis Points:</strong></p>\n    <ul>\n      <li><strong>Pros:</strong> Helps set new goals to compete → Secures finance from a bank → Identifies what resources are needed → Helps measure success against objectives</li>\n      <li><strong>Cons:</strong> Takes significant time to write → Opportunity cost (time away from customers) → May quickly become outdated → No guarantee of success</li>\n    </ul>\n    <p><strong>❌ Common Mistake:</strong> Only writing advantages, or only writing disadvantages. You need both for full marks.</p>\n    <p><strong>🚫 Avoid vague analysis:</strong> \"It helps the business\" or \"it makes things easier\" are not specific business impacts. Always say <em>what</em> improves — costs, revenue, customer numbers, market share, etc.</p>", "question": "What combination of points is needed to earn full Analysis marks in a 9-mark question about a business plan?", "options": ["Two disadvantages and no advantages", "One vague statement that ''it helps the business''", "Two advantages and no disadvantages", "One business-facing advantage and one disadvantage"]}'::jsonb, '{"answer": 3, "explain": "Full Analysis marks require one pro AND one con — only writing advantages or only disadvantages misses out on the full 2 marks."}'::jsonb),
('business:1-2-business-planning:tips:1c6537d2', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — The Four-Paragraph Structure for Full Marks", "reading": "<p>A 9-mark evaluation question is the highest-tariff question on the paper. Marks are split across <strong>Knowledge, Understanding, Application (quantitative), Analysis, and Evaluation</strong>. Structure your answer in four paragraphs:</p>\n    <p><strong>Paragraph 1 — K & U:</strong><br/>Define the key term and explain what it contains.<br/><em>\"A business plan is a document (K) that contains details of the business''s aims, target market, finance, and market research (U).\"</em></p>\n    <p><strong>Paragraph 2 — AN & APP (Advantage):</strong><br/>Give one reason FOR writing the plan, applied to the specific business with data.<br/><em>\"One advantage of writing a new plan is that it would help SJ Salon set new strategies to compete. 42% of customers (APP) would consider using the new competitor if its prices were lower — so the salon needs a clear plan to retain these customers (AN).\"</em></p>\n    <p><strong>Paragraph 3 — AN & APP (Disadvantage):</strong><br/>Give one reason AGAINST, applied to the business with data.<br/><em>\"However, writing the plan will take Sam 30 hours — 75% of a full working week (APP). This is time he will not spend serving customers, which is an opportunity cost that could cost the salon revenue (AN).\"</em></p>\n    <p><strong>Paragraph 4 — Evaluation (3 marks):</strong><br/>Make a <strong>clear, explicit decision</strong> (1) + valid justification (1) + contextual justification (1).<br/><em>\"Overall, I think Sam SHOULD write a new business plan (DECISION). The arrival of a national hairdressing chain is a significant change to SJ Salon''s competitive environment (CONTEXT), and without a plan, the partners have no clear strategy for retaining their customers and could lose a substantial proportion of their revenue (REASONING/IMPACT).\"</em></p>\n    <p><strong>⚠️ Examiner''s Warning:</strong> The most common reason for losing Evaluation marks was \"sitting on the fence\" — giving reasons for and against but never stating a final decision. You MUST make a clear choice.</p>", "question": "According to examiners, what is the most common reason students lose Evaluation marks in a 9-mark question?", "options": ["Giving reasons without ever deciding", "Quoting too much from the case study", "Writing far too short an introduction", "Using too many calculations"]}'::jsonb, '{"answer": 0, "explain": "The examiner''s warning states the most common reason for losing Evaluation marks was ''sitting on the fence'' — never making a clear final decision."}'::jsonb),
('business:1-2-business-planning:tips:1c8b9747', 'business', 'business:1-2-business-planning', '1.2 Business Planning', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 9 marks — Evaluating a Business Plan''s Effectiveness", "reading": "<p>When asked to evaluate <strong>how effective a specific business plan is</strong> (e.g. Shirtz Ltd or Dunning Golf Club), use this framework:</p>\n    <ul>\n      <li><strong>What is good about it?</strong> Which sections are present and well-developed?</li>\n      <li><strong>What is missing or weak?</strong> Are any key sections absent? Is the detail sufficient?</li>\n      <li><strong>Are the objectives SMART?</strong> Vague goals like \"grow the business\" are not measurable — this is a critical weakness.</li>\n      <li><strong>Does the missing content matter for this specific business?</strong> A missing competitor analysis is especially damaging if the business is entering a competitive market.</li>\n    </ul>\n    <p><strong>✅ Example Evaluation Sentence:</strong><br/><em>\"Overall, the Shirtz Ltd business plan is only partially effective (DECISION). While it identifies the need for new finance and the target pricing strategy, it lacks the financial detail (such as cash flow forecasts) that a bank would need before agreeing to lend money (CONTEXT + IMPACT). Without this, the plan may not help Shirtz Ltd achieve its core objective of expansion (REASONING).\"</em></p>", "question": "When evaluating how effective a specific business plan is, why is a missing competitor analysis especially damaging?", "options": ["It always results in an automatic mark of zero", "If entering a competitive market, this gap matters more", "It only matters for analyse questions, not evaluate ones", "Competitor analysis is never part of a business plan"]}'::jsonb, '{"answer": 1, "explain": "The framework notes that missing content matters more when it is directly relevant to the business''s specific situation — e.g. a missing competitor analysis is especially damaging for a business entering a crowded market."}'::jsonb),
