('business:1-3-business-ownership:match:1a439eb6', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sole Trader”?", "options": ["A business owned by two or more people who share capital, skills, and unlimited liability.", "A company whose shares can only be sold to family and friends with shareholder agreement. Has ''Ltd'' after its name and limited liability.", "A business owned by one person. Can employ staff. Has unlimited liability. Most common form of ownership in the UK.", "A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital."]}'::jsonb, '{"answer": 2, "explain": "“Sole Trader” means: A business owned by one person. Can employ staff. Has unlimited liability. Most common form of ownership in the UK."}'::jsonb),
('business:1-3-business-ownership:match:daa81779', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Partnership”?", "options": ["A company whose shares can only be sold to family and friends with shareholder agreement. Has ''Ltd'' after its name and limited liability.", "A business owned by two or more people who share capital, skills, and unlimited liability.", "A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital.", "The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected."]}'::jsonb, '{"answer": 1, "explain": "“Partnership” means: A business owned by two or more people who share capital, skills, and unlimited liability."}'::jsonb),
('business:1-3-business-ownership:match:13b8b8cc', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Private Limited Company (Ltd)”?", "options": ["A company whose shares can only be sold to family and friends with shareholder agreement. Has ''Ltd'' after its name and limited liability.", "A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital.", "The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected.", "The owner is personally responsible for ALL debts of the business. Personal possessions can be seized to repay creditors."]}'::jsonb, '{"answer": 0, "explain": "“Private Limited Company (Ltd)” means: A company whose shares can only be sold to family and friends with shareholder agreement. Has ''Ltd'' after its name and limited liability."}'::jsonb),
('business:1-3-business-ownership:match:71887e22', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Public Limited Company (plc)”?", "options": ["The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected.", "The owner is personally responsible for ALL debts of the business. Personal possessions can be seized to repay creditors.", "A legal document setting out each partner''s role, capital contribution, and how profits and losses will be shared.", "A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital."]}'::jsonb, '{"answer": 3, "explain": "“Public Limited Company (plc)” means: A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital."}'::jsonb),
('business:1-3-business-ownership:match:a0cf4c06', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Limited Liability”?", "options": ["The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected.", "The owner is personally responsible for ALL debts of the business. Personal possessions can be seized to repay creditors.", "A legal document setting out each partner''s role, capital contribution, and how profits and losses will be shared.", "The owners of a limited company. Each has invested money and owns a proportion of the business."]}'::jsonb, '{"answer": 0, "explain": "“Limited Liability” means: The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected."}'::jsonb),
