('business:1-3-business-ownership:match:25e751f2', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Deed of Partnership”?", "options": ["A legal document setting out each partner''s role, capital contribution, and how profits and losses will be shared.", "The owners of a limited company. Each has invested money and owns a proportion of the business.", "A payment made to shareholders from the profits of a limited company. The financial reward for investing (and taking a risk).", "A partner who provides capital for a partnership but takes no active role in running the business."]}'::jsonb, '{"answer": 0, "explain": "“Deed of Partnership” means: A legal document setting out each partner''s role, capital contribution, and how profits and losses will be shared."}'::jsonb)
